def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            score += (1 - ratio) ** 4 * 20
            for x in range(1, 6):
                score += np.cos(ratio * x * np.pi / 2) * x * 0.7
            if capacity % 4 == 0:
                score += np.sqrt(capacity) * 1.5
        elif 0.2 <= ratio < 0.5:
            score += np.exp(-ratio) * 10
            factors = [k for k in range(1, int(capacity)+1) if capacity % k == 0]
            for f in factors:
                if f < item:
                    score += f * 0.05
                elif f > item:
                    score -= f * 0.02
            for y in range(1,4):
                score += ((-1) ** y) * np.sin(ratio * y * np.pi) * 4
        elif 0.5 <= ratio <= 0.8:
            score += np.log1p(ratio*5) * 12
            primes = []
            for num in range(2, int(capacity)+1):
                prime = True
                for div in range(2, int(np.sqrt(num))+1):
                    if num % div == 0:
                        prime = False
                        break
                if prime and num <= capacity:
                    primes.append(num)
            for p in primes:
                if p < item:
                    score += p * 0.3
                else:
                    score -= p * 0.1
            for z in range(1, 5):
                score += ((ratio * z) % 1) * z * 2
        elif 0.8 < ratio <= 1.0:
            score += (np.tanh((1.2-ratio)*10) + 1) * 15
            for n in range(1, int(capacity)+1):
                if n % 3 == 0 or n % 5 == 0:
                    score += np.log1p(n) * 0.4
            divisors = [d for d in range(1, int(capacity//2)+1) if capacity % d == 0]
            for d in divisors:
                if d % 2 == 1:
                    score += d * 0.2
                else:
                    score -= d * 0.1
        else:
            penalty = 0
            int_ratio = int(ratio)
            for j in range(1, int_ratio + 2):
                if j == 0:
                    continue
                if abs((ratio * 10) % j) < 1e-5:
                    penalty += j * 3
                else:
                    penalty -= (j % 3) * 1.5
            penalty += sum([np.sin(ratio * k) for k in range(1,7)]) * 4
            score = penalty + (ratio - 1) * 35
            if ratio > 2.5:
                for m in range(1, 6):
                    if m % 2 == 0:
                        score += np.tanh(ratio / (m + 0.3)) * 7
                    else:
                        score -= np.cosh(ratio / (m + 0.5)) * 0.5
            if capacity % 7 == 0:
                score *= 1.15
            if int(capacity) % 11 == 0 and ratio < 3:
                score *= 0.85
        if capacity > 50:
            score *= 1.05
            for q in range(1, 4):
                score += np.sqrt(q * ratio) * 1.2
        else:
            for r in range(1, 3):
                score -= np.log1p(r * capacity) * 0.8
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    return priorities
